<script setup lang="ts">
import {reactive,ref} from 'vue';import {useRouter} from 'vue-router';import {api} from '../api.ts'
const router=useRouter();const form=reactive({username:'admin',password:''});const loading=ref(false);const error=ref('');const login=async()=>{loading.value=true;error.value='';try{const body=new URLSearchParams();body.append('username',form.username);body.append('password',form.password);await api.post('/auth/login',body,{headers:{'Content-Type':'application/x-www-form-urlencoded'}});router.push('/')}catch(e:any){error.value=e.response?.status===401?'用户名或密码错误':'登录失败，请重试'}finally{loading.value=false}}
</script>
<template><div class="login"><el-form class="login-card" @submit.prevent="login"><h1>管理后台</h1><el-form-item><el-input v-model="form.username" placeholder="用户名"/></el-form-item><el-form-item><el-input v-model="form.password" type="password" show-password placeholder="密码"/></el-form-item><el-button native-type="submit" type="primary" :loading="loading" style="width:100%">登录</el-button><p v-if="error" style="color:#d93025;text-align:center;margin-top:12px">{{ error }}</p></el-form></div></template>
